function bookingScanHelperUrl() {
  if (canUseLocalBackend()) return "/api/scan-booking";
  if (window.location.protocol.startsWith("http")) return "/.netlify/functions/scan-booking";
  return "";
}

function showTravelScanBookingDialog(trip) {
  const d = document.createElement("dialog");
  d.className = "recipe-dialog auth-dialog";
  d.innerHTML =
    '<div class="recipe-form">' +
    '<h3 style="margin:0 0 4px">Scan Booking Confirmation</h3>' +
    '<p style="margin:0 0 14px;font-size:0.85rem;color:var(--text-muted)">Upload a screenshot or photo of a flight, hotel, rental, or any booking confirmation.</p>' +
    '<label class="travel-scan-upload-area" id="tsbUploadArea">' +
    '<input type="file" id="tsbFileInput" accept="image/*,.pdf,application/pdf" style="display:none" />' +
    '<span id="tsbUploadLabel">📷 Choose image or PDF</span>' +
    '</label>' +
    '<img id="tsbPreview" style="display:none;max-width:100%;max-height:180px;object-fit:contain;border-radius:8px;margin-top:10px" />' +
    '<div id="tsbStatus" style="font-size:0.85rem;color:var(--text-muted);min-height:1.2em;margin-top:8px"></div>' +
    '<div style="display:flex;gap:8px;justify-content:flex-end;margin-top:16px">' +
    '<button type="button" class="secondary-btn" id="tsbCancel">Cancel</button>' +
    '<button type="button" class="primary-btn" id="tsbScan" disabled>Scan</button>' +
    '</div>' +
    '</div>';
  document.body.appendChild(d);
  d.showModal();

  const fileInput = d.querySelector("#tsbFileInput");
  const uploadArea = d.querySelector("#tsbUploadArea");
  const uploadLabel = d.querySelector("#tsbUploadLabel");
  const preview = d.querySelector("#tsbPreview");
  const statusEl = d.querySelector("#tsbStatus");
  const scanBtn = d.querySelector("#tsbScan");
  let selectedFile = null;

  function fileIsPdf(file) {
    return file.type === "application/pdf" || file.name.toLowerCase().endsWith(".pdf");
  }

  fileInput.addEventListener("change", () => {
    selectedFile = fileInput.files[0] || null;
    if (!selectedFile) return;
    if (fileIsPdf(selectedFile)) {
      preview.style.display = "none";
      uploadLabel.textContent = "📄 " + selectedFile.name;
    } else {
      uploadLabel.textContent = selectedFile.name;
      const reader = new FileReader();
      reader.onload = e => { preview.src = e.target.result; preview.style.display = "block"; };
      reader.readAsDataURL(selectedFile);
    }
    scanBtn.disabled = false;
    statusEl.textContent = "";
  });

  d.querySelector("#tsbCancel").addEventListener("click", () => d.remove());
  scanBtn.addEventListener("click", async () => {
    if (!selectedFile) return;
    const url = bookingScanHelperUrl();
    if (!url) { statusEl.textContent = "Scanning not available here."; return; }
    scanBtn.disabled = true;
    statusEl.textContent = "Scanning… this takes a few seconds.";
    try {
      let dataUrl;
      if (fileIsPdf(selectedFile)) {
        const raw = await fileToDataUrl(selectedFile);
        // Normalize to application/pdf regardless of what the browser reports
        dataUrl = raw.replace(/^data:[^;]*;base64,/, "data:application/pdf;base64,");
      } else {
        dataUrl = await fileToDataUrl(await prepareScanImage(selectedFile, {}, { maxDimension: 1600, quality: 0.82 }));
      }
      const res = await fetch(url, {
        method: "POST",
        headers: { "content-type": "application/json", Authorization: "Bearer " + (authSession?.access_token || "") },
        body: JSON.stringify({ images: [dataUrl] })
      });
      const payload = await res.json().catch(() => ({}));
      if (!res.ok) throw new Error(payload.error || "Scan failed.");
      d.remove();
      showTravelBookingReviewDialog(trip, payload.booking);
    } catch (err) {
      statusEl.textContent = err.message || "Scan failed. Try a clearer image.";
      scanBtn.disabled = false;
    }
  });
}

function showTravelBookingReviewDialog(trip, booking) {
  const logTypes = ["flight", "hotel", "car", "train", "ferry", "other"];
  const optionsHtml = logTypes.map(function(t) {
    return '<option value="' + t + '"' + (booking.type === t ? ' selected' : '') + '>' + t.charAt(0).toUpperCase() + t.slice(1) + '</option>';
  }).join('');

  const d = document.createElement("dialog");
  d.className = "recipe-dialog auth-dialog";
  const isCar   = booking.type === 'car';
  const isHotel = booking.type === 'hotel';
  d.innerHTML =
    '<div class="recipe-form">' +
    '<h3 style="margin:0 0 4px">Review Booking</h3>' +
    '<p style="margin:0 0 14px;font-size:0.85rem;color:var(--text-muted)">Edit anything before saving to your trip.</p>' +
    '<div class="travel-dialog-field"><label>Type</label><select id="tbrType" class="text-input">' + optionsHtml + '</select></div>' +
    '<div class="travel-dialog-field"><label>' + (isCar ? 'Rental Company' : 'Title') + '</label><input id="tbrTitle" class="text-input" value="' + escapeHtml(booking.title) + '" /></div>' +
    '<div class="travel-dialog-field"><label>Confirmation #</label><input id="tbrConf" class="text-input" value="' + escapeHtml(booking.confirmation) + '" /></div>' +
    (isCar
      ? '<div style="display:flex;gap:8px">' +
        '<div class="travel-dialog-field" style="flex:1"><label>Pick-up Date</label><input id="tbrStart" type="date" class="text-input" value="' + (booking.startDate || '') + '" /></div>' +
        '<div class="travel-dialog-field" style="flex:1"><label>Drop-off Date</label><input id="tbrEnd" type="date" class="text-input" value="' + (booking.endDate || '') + '" /></div>' +
        '</div>' +
        '<div class="travel-dialog-field"><label>Pick-up Location</label><input id="tbrPickupLoc" class="text-input" value="' + escapeHtml(booking.pickupLocation || booking.location || '') + '" placeholder="e.g. LAX Airport, Terminal 2" /></div>' +
        '<div class="travel-dialog-field"><label>Drop-off Location</label><input id="tbrDropoffLoc" class="text-input" value="' + escapeHtml(booking.dropoffLocation || '') + '" placeholder="If different from pick-up" /></div>' +
        '<div style="display:flex;gap:8px">' +
        '<div class="travel-dialog-field" style="flex:1"><label>Vehicle Type</label><input id="tbrVehicleType" class="text-input" value="' + escapeHtml(booking.vehicleType || '') + '" placeholder="e.g. Compact SUV" /></div>' +
        '<div class="travel-dialog-field" style="flex:1"><label>Mileage</label><input id="tbrMileage" class="text-input" value="' + escapeHtml(booking.mileage || '') + '" placeholder="e.g. Unlimited" /></div>' +
        '</div>' +
        '<div class="travel-dialog-field"><label>Total Cost ($)</label><input id="tbrCost" type="number" min="0" class="text-input" value="' + (booking.cost || 0) + '" /></div>'
      : isHotel
        ? '<div style="display:flex;gap:8px">' +
          '<div class="travel-dialog-field" style="flex:1"><label>Check-in</label><input id="tbrStart" type="date" class="text-input" value="' + (booking.startDate || '') + '" /></div>' +
          '<div class="travel-dialog-field" style="flex:1"><label>Check-out</label><input id="tbrEnd" type="date" class="text-input" value="' + (booking.endDate || '') + '" /></div>' +
          '</div>' +
          '<div class="travel-dialog-field"><label>Cost ($)</label><input id="tbrCost" type="number" min="0" class="text-input" value="' + (booking.cost || 0) + '" /></div>' +
          '<div class="travel-dialog-field"><label>Address</label><input id="tbrLocation" class="text-input" value="' + escapeHtml(booking.location || '') + '" placeholder="e.g. 123 Main St, Istanbul" /></div>'
        : '<div style="display:flex;gap:8px">' +
          '<div class="travel-dialog-field" style="flex:1"><label>Date</label><input id="tbrStart" type="date" class="text-input" value="' + (booking.startDate || '') + '" /></div>' +
          '<div class="travel-dialog-field" style="flex:1"><label>Cost ($)</label><input id="tbrCost" type="number" min="0" class="text-input" value="' + (booking.cost || 0) + '" /></div>' +
          '</div>' +
          '<div class="travel-dialog-field"><label>Location / Address</label><input id="tbrLocation" class="text-input" value="' + escapeHtml(booking.location || '') + '" placeholder="e.g. 123 Main St, Tokyo" /></div>') +
    '<div class="travel-dialog-field"><label>Notes</label><input id="tbrNotes" class="text-input" value="' + escapeHtml(booking.notes) + '" /></div>' +
    (booking.segments && booking.segments.length
      ? '<div style="margin-top:12px"><div style="font-size:0.75rem;font-weight:600;text-transform:uppercase;letter-spacing:0.05em;color:var(--text-muted);margin-bottom:6px">Flight segments</div>' +
        '<div style="font-size:0.82rem;line-height:1.8;color:var(--text)">' +
        booking.segments.map(function(s) {
          var line = '✈️ ' + escapeHtml(s.from) + ' → ' + escapeHtml(s.to);
          if (s.fromName || s.toName) line += ' <span style="color:var(--text-muted)">(' + escapeHtml(s.fromName || s.from) + ' → ' + escapeHtml(s.toName || s.to) + ')</span>';
          if (s.departDate) line += ' &nbsp;' + escapeHtml(formatTravelDate(s.departDate));
          if (s.departTime) line += ' ' + escapeHtml(s.departTime);
          if (s.arriveTime) line += ' → ' + escapeHtml(s.arriveTime);
          if (s.arriveDate && s.arriveDate !== s.departDate) line += ' <span style="color:var(--text-muted)">(' + escapeHtml(formatTravelDate(s.arriveDate)) + ')</span>';
          if (s.flightNumber) line += ' &nbsp;<span style="color:var(--text-muted)">' + escapeHtml(s.flightNumber) + '</span>';
          return '<div>' + line + '</div>';
        }).join('') +
        '</div></div>'
      : '') +
    '<label style="display:flex;align-items:center;gap:8px;font-size:0.88rem;margin-top:14px;cursor:pointer">' +
    '<input type="checkbox" id="tbrSyncItinerary" checked style="width:15px;height:15px;accent-color:var(--accent)" />' +
    (booking.segments && booking.segments.length
      ? 'Add each flight leg to itinerary'
      : booking.type === 'hotel'
        ? 'Set hotel location on itinerary days'
        : booking.type === 'car'
          ? 'Add pick-up & drop-off to itinerary'
          : 'Add to itinerary') +
    '</label>' +
    '<div style="display:flex;gap:8px;justify-content:flex-end;margin-top:16px">' +
    '<button type="button" class="secondary-btn" id="tbrCancel">Cancel</button>' +
    '<button type="button" class="primary-btn" id="tbrSave">Add to trip</button>' +
    '</div>' +
    '</div>';
  document.body.appendChild(d);
  d.showModal();

  d.querySelector("#tbrCancel").addEventListener("click", () => d.remove());
  d.querySelector("#tbrSave").addEventListener("click", () => {
    if (!Array.isArray(trip.logistics)) trip.logistics = [];
    const savedType = d.querySelector("#tbrType").value;
    const savedIsCar = savedType === "car";
    const entry = {
      id: createId("tlog"),
      type: savedType,
      title: d.querySelector("#tbrTitle").value.trim(),
      confirmation: d.querySelector("#tbrConf").value.trim(),
      startDate: d.querySelector("#tbrStart")?.value || "",
      endDate: d.querySelector("#tbrEnd")?.value || booking.endDate || "",
      cost: parseFloat(d.querySelector("#tbrCost").value) || 0,
      location: savedIsCar
        ? (d.querySelector("#tbrPickupLoc")?.value.trim() || "")
        : (d.querySelector("#tbrLocation")?.value.trim() || ""),
      notes: d.querySelector("#tbrNotes").value.trim(),
      ...(savedIsCar ? {
        pickupLocation: d.querySelector("#tbrPickupLoc")?.value.trim() || "",
        dropoffLocation: d.querySelector("#tbrDropoffLoc")?.value.trim() || "",
        vehicleType: d.querySelector("#tbrVehicleType")?.value.trim() || "",
        mileage: d.querySelector("#tbrMileage")?.value.trim() || ""
      } : {}),
      ...(savedType === "flight" && booking.segments?.length ? { segments: booking.segments } : {})
    };
    trip.logistics.push(entry);

    // Auto-populate Stays tab when saving a hotel/accommodation booking
    if (savedType === "hotel") {
      if (!Array.isArray(trip.stays)) trip.stays = [];
      const dupStay = entry.confirmation
        ? trip.stays.find(function(s) { return s.confirmation && s.confirmation === entry.confirmation; })
        : null;
      if (!dupStay) {
        trip.stays.push({
          id: createId("tstay"),
          type: "hotel",
          name: entry.title || "",
          checkIn: entry.startDate || "",
          checkOut: entry.endDate || "",
          address: entry.location || "",
          bookingUrl: entry.bookingUrl || "",
          confirmation: entry.confirmation || "",
          amenities: [],
          notes: entry.notes || "",
          cost: entry.cost || 0,
        });
      }
    }

    // Auto-update trip dates if blank and booking has a start date
    if (entry.startDate) {
      if (!trip.startDate || entry.startDate < trip.startDate) {
        trip.startDate = entry.startDate;
        syncTripToCalendar(trip);
      }
      const endDate = entry.endDate || booking.endDate;
      if (endDate && (!trip.endDate || endDate > trip.endDate)) {
        trip.endDate = endDate;
        syncTripToCalendar(trip);
      }
    }

    // Auto-add expense if cost > 0
    if (entry.cost > 0) {
      if (!Array.isArray(trip.expenses)) trip.expenses = [];
      const catMap = { flight: "flights", hotel: "accommodation", car: "transport", train: "transport", ferry: "transport", other: "other" };
      trip.expenses.push({
        id: createId("texp"),
        description: entry.title || entry.type,
        amount: entry.cost,
        category: catMap[entry.type] || "other",
        date: entry.startDate || dateKeyFromDate(new Date())
      });
    }

    // Sync to itinerary if requested
    var syncResult = null;
    if (d.querySelector("#tbrSyncItinerary")?.checked) {
      syncResult = syncLogisticToItinerary(trip, entry, booking);
    }

    trip.updatedAt = new Date().toISOString();
    persist();
    d.remove();
    if (activeAppArea === "explore") openExploreTrip(trip.id);
  });
}

